class Solution:
    def minCost(self, n: int, cuts) -> int:
        points = sorted(cuts)
        points = [0] + points + [n]
        m = len(points)
        dp = [[0] * m for _ in range(m)]
        for length in range(2, m):
            for i in range(0, m - length):
                j = i + length
                if j - i <= 1:
                    continue
                best = min(dp[i][k] + dp[k][j] for k in range(i + 1, j))
                dp[i][j] = best + (points[j] - points[i])
        return dp[0][m - 1]

