import functools

class Solution:
    def minCost(self, n: int, cuts) -> int:
        points = sorted(cuts)
        points = [0] + points + [n]
        m = len(points)

        @functools.lru_cache(maxsize=None)
        def dp(i, j):
            if j - i <= 1:
                return 0
            best = min(dp(i, k) + dp(k, j) for k in range(i + 1, j))
            return best + (points[j] - points[i])

        result = dp(0, m - 1)
        dp.cache_clear()
        return result

