var minCost = function(n, cuts) {
    const points = cuts.slice().sort((a, b) => a - b);
    points.unshift(0);
    points.push(n);
    const m = points.length;
    const memo = new Map();
    function dp(i, j) {
        if (j - i <= 1) return 0;
        const key = i * m + j;
        if (memo.has(key)) return memo.get(key);
        let best = Infinity;
        for (let k = i + 1; k < j; k++) {
            const cost = dp(i, k) + dp(k, j);
            if (cost < best) best = cost;
        }
        const result = best + (points[j] - points[i]);
        memo.set(key, result);
        return result;
    }
    return dp(0, m - 1);
};
